-- Create Sequence
CREATE SEQUENCE emp_seq
START WITH 1000
INCREMENT BY 1
MAXVALUE 999999
NOCACHE
NOCYCLE;

-- Use sequence for inserts
INSERT INTO employees (employee_id, first_name, last_name)
VALUES (emp_seq.NEXTVAL, 'John', 'Smith');

-- Create Synonym
CREATE SYNOPSIS emp_syn FOR employees;

-- Create Public Synonym
CREATE PUBLIC SYNOPSIS dept_syn FOR hr.departments;

-- Using synonym in queries
SELECT * FROM emp_syn;

-- Drop sequence and synonym
DROP SEQUENCE emp_seq;
DROP SYNONYM emp_syn;

-- Start transaction
INSERT INTO departments VALUES (280, 'Training', NULL, 1700);

-- Create savepoint
SAVEPOINT sp1;

-- More operations
INSERT INTO employees VALUES (300, 'David', 'Lee', 'dlee', '123456', 
 SYSDATE, 'IT_PROG', 5000, NULL, 100, 60);

-- Check data
SELECT * FROM departments WHERE department_id = 280;

-- Rollback to savepoint
ROLLBACK TO sp1;

-- Now only department insert is visible, not employee
SELECT * FROM departments WHERE department_id = 280;

-- Commit the transaction
COMMIT;

-- Alternative: Complete rollback
ROLLBACK; -- Undoes all changes since last COMMIT

-- Grant object privileges
GRANT SELECT, INSERT ON employees TO user_john;
GRANT UPDATE (salary, commission_pct) ON employees TO user_john;
GRANT EXECUTE ON compute_bonus TO user_john;

-- Grant with grant option
GRANT SELECT ON departments TO user_john WITH GRANT OPTION;

-- Grant system privileges
GRANT CREATE TABLE TO user_john;
GRANT CREATE VIEW TO user_john;
GRANT CREATE PROCEDURE TO user_john;

-- View granted privileges
SELECT * FROM user_tab_privs_made;
SELECT * FROM user_sys_privs;

-- Revoke privileges
REVOKE SELECT ON employees FROM user_john;
REVOKE CREATE TABLE FROM user_john;
